import React, { useEffect, useState, useCallback } from 'react';
import {
  Card,
  Button,
  dispatchAppToast,
} from '@linm-soft-org/linm-web-common-components';
import {
  Title,
  Text,
  Tag,
  Tooltip,
  Space,
  Popconfirm,
  Spin,
} from '@/components/common';
import { fpcService } from '../../../services/fpc/service';
import type { CostPlanItemDto, CostCodeDto } from '../../../services/fpc/types';
import { useAppDispatch } from '../../../store/hooks';
import styles from './CostPlanPage.module.css';

const GROUP_ORDER = ['Thu nhập', 'Chi phí'];
const PRIORITY_ORDER = ['Critical', 'High', 'Medium', 'Low'];

function formatMoney(v?: number) {
  if (v === undefined || v === null) return '-';
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(v);
}

function formatPercent(v?: number | null) {
  if (v === undefined || v === null || isNaN(v)) return '-';
  return `${v >= 0 ? '+' : ''}${v.toFixed(1)}%`;
}

function getStatusInfo(variancePct: number | null | undefined): { label: string; color: string } {
  if (variancePct === null || variancePct === undefined) {
    return { label: 'Chưa xác định', color: '#999' };
  }
  if (variancePct < -10) return { label: 'Ít hơn', color: '#faad14' };        // vàng
  if (variancePct <= 10) return { label: 'Đạt', color: '#52c41a' };           // xanh
  return { label: 'Nhiều hơn', color: '#ff4d4f' };                            // đỏ
}

interface PlanGroup {
  groupName: string;
  items: CostPlanItemDto[];
  totalMustPay: number;
  totalPlanned: number;
  totalDebt: number;
  totalActual: number;
}

function groupAndSort(items: CostPlanItemDto[]): PlanGroup[] {
  const groups: Record<string, CostPlanItemDto[]> = {};
  items.forEach((item) => {
    const g = item.groupName || 'Chi phí';
    if (!groups[g]) groups[g] = [];
    groups[g].push(item);
  });

  return GROUP_ORDER
    .filter((g) => groups[g]?.length)
    .map((groupName) => {
      const sorted = groups[groupName].sort((a, b) => {
        const pa = PRIORITY_ORDER.indexOf(a.priority || 'Medium');
        const pb = PRIORITY_ORDER.indexOf(b.priority || 'Medium');
        return pa - pb;
      });
      return {
        groupName,
        items: sorted,
        totalMustPay: sorted.reduce((s, i) => s + i.mustPay, 0),
        totalPlanned: sorted.reduce((s, i) => s + i.plannedAmount, 0),
        totalDebt: sorted.reduce((s, i) => s + i.debt, 0),
        totalActual: sorted.reduce((s, i) => s + i.actualAmount, 0),
      };
    });
}

export default function CostPlanPage() {
  const dispatch = useAppDispatch();
  const [items, setItems] = useState<CostPlanItemDto[]>([]);
  const [costCodes, setCostCodes] = useState<CostCodeDto[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  // Filters
  const now = new Date();
  const [year, setYear] = useState(now.getFullYear());
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [branchCode, setBranchCode] = useState('');

  // Group filter tab
  const [activeGroup, setActiveGroup] = useState<string | null>(null);

  // Edit state
  const [editMode, setEditMode] = useState(false);
  const [editValues, setEditValues] = useState<Record<string, { planned: string; mustPay: string }>>({});

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const [planItems, codes] = await Promise.all([
        fpcService.getCostPlanList({ year, month, branchCode: branchCode || undefined }),
        fpcService.getCostCodeList(),
      ]);
      setItems(planItems);
      setCostCodes(codes);
    } finally {
      setLoading(false);
    }
  }, [year, month, branchCode]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleEnterEdit = () => {
    const values: Record<string, { planned: string; mustPay: string }> = {};
    // Pre-fill from existing items
    items.forEach((item) => {
      values[item.costCode] = { planned: String(item.plannedAmount), mustPay: String(item.mustPay) };
    });
    // Add missing cost codes
    costCodes.filter((cc) => cc.isActive).forEach((cc) => {
      if (!values[cc.code]) {
        values[cc.code] = { planned: '0', mustPay: '0' };
      }
    });
    setEditValues(values);
    setEditMode(true);
  };

  const handleCancelEdit = () => {
    setEditMode(false);
    setEditValues({});
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const lines = Object.entries(editValues)
        .filter(([_, val]) => {
          const p = parseFloat(val.planned);
          const m = parseFloat(val.mustPay);
          return p > 0 || m > 0;
        })
        .map(([costCode, val]) => ({
          costCode,
          plannedAmount: parseFloat(val.planned) || 0,
          mustPay: parseFloat(val.mustPay) || 0,
          note: undefined as string | undefined,
        }));

      if (lines.length === 0) {
        dispatchAppToast(dispatch, { message: 'Chưa có dữ liệu để lưu', type: 'warning' });
        return;
      }

      await fpcService.batchUpsertCostPlans({
        year,
        month,
        branchCode: branchCode || 'HQ',
        lines,
      });

      dispatchAppToast(dispatch, { message: 'Đã lưu kế hoạch chi phí', type: 'success' });
      setEditMode(false);
      fetchData();
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    await fpcService.deleteCostPlan(id);
    dispatchAppToast(dispatch, { message: 'Đã xóa khoản dự kiến', type: 'success' });
    fetchData();
  };

  const handleEditChange = (costCode: string, field: 'planned' | 'mustPay', value: string) => {
    setEditValues((prev) => ({
      ...prev,
      [costCode]: { ...prev[costCode], [field]: value },
    }));
  };

  // Determine available groups
  const allGroups = GROUP_ORDER.filter((g) => costCodes.some((cc) => (cc.groupName || 'Chi phí') === g));
  const filteredGroup = activeGroup && allGroups.includes(activeGroup) ? activeGroup : null;

  // Resolve items
  const allItems = items;
  const groups = groupAndSort(filteredGroup ? allItems.filter((i) => (i.groupName || 'Chi phí') === filteredGroup) : allItems);
  const grandTotalPlanned = allItems.reduce((s, i) => s + i.plannedAmount, 0);
  const grandTotalMustPay = allItems.reduce((s, i) => s + i.mustPay, 0);
  const grandTotalDebt = allItems.reduce((s, i) => s + i.debt, 0);
  const grandTotalActual = allItems.reduce((s, i) => s + i.actualAmount, 0);

  // Edit mode: build list of cost codes filtered by group
  const editCostCodes = filteredGroup
    ? costCodes.filter((cc) => (cc.groupName || 'Chi phí') === filteredGroup && cc.isActive)
    : costCodes.filter((cc) => cc.isActive);
  const sortedEditCodes = [...editCostCodes].sort((a, b) => {
    const ga = GROUP_ORDER.indexOf(a.groupName || 'Chi phí');
    const gb = GROUP_ORDER.indexOf(b.groupName || 'Chi phí');
    if (ga !== gb) return ga - gb;
    const pa = PRIORITY_ORDER.indexOf(a.priority || 'Medium');
    const pb = PRIORITY_ORDER.indexOf(b.priority || 'Medium');
    return pa - pb;
  });

  const renderViewMode = () => {
    if (allItems.length === 0) {
      return (
        <div className={styles.emptyState}>
          <p>Chưa có dữ liệu cho kỳ này. Nhấn "Khai báo" để nhập số dự kiến.</p>
        </div>
      );
    }

    return groups.map((group) => (
      <div key={group.groupName} className={styles.groupSection}>
        <div className={styles.groupHeader}>
          <Text strong>{group.groupName}</Text>
        </div>
        <table className={styles.table}>
          <thead>
            <tr>
              <th className={styles.thStt}>STT</th>
              <th className={styles.thItem}>Khoản mục</th>
              <th className={styles.thMustPay}>Phải chi</th>
              <th className={styles.thPlanned}>Dự chi</th>
              <th className={styles.thDebt}>Nợ</th>
              <th className={styles.thActual}>Thực chi</th>
              <th className={styles.thPctPlanned}>%(dự chi)</th>
              <th className={styles.thPctMustPay}>%(phải chi)</th>
              <th className={styles.thStatus}>Trạng thái</th>
              <th className={styles.thPriority}>Mức độ</th>
              <th className={styles.thActions}></th>
            </tr>
          </thead>
          <tbody>
            {group.items.map((item, idx) => {
              const variancePct = item.plannedAmount > 0
                ? ((item.actualAmount - item.plannedAmount) / item.plannedAmount) * 100
                : null;
              const status = getStatusInfo(variancePct);
              const pctOfPlanned = item.plannedAmount > 0
                ? (item.actualAmount / item.plannedAmount) * 100
                : null;
              const pctOfMustPay = item.mustPay > 0
                ? (item.actualAmount / item.mustPay) * 100
                : null;

              return (
                <tr key={item.id}>
                  <td className={styles.cellStt}>{idx + 1}</td>
                  <td className={styles.cellItem}>
                    <Text strong>{item.costCode}</Text>
                    {item.costCodeName ? <span className={styles.itemName}> — {item.costCodeName}</span> : null}
                  </td>
                  <td className={styles.cellMoney}>{formatMoney(item.mustPay)}</td>
                  <td className={styles.cellMoney}>{formatMoney(item.plannedAmount)}</td>
                  <td className={styles.cellMoney} style={{ color: item.debt > 0 ? '#ff4d4f' : '#52c41a' }}>
                    {formatMoney(item.debt)}
                  </td>
                  <td className={styles.cellMoney}>{formatMoney(item.actualAmount)}</td>
                  <td className={styles.cellPct}>{formatPercent(pctOfPlanned)}</td>
                  <td className={styles.cellPct}>{formatPercent(pctOfMustPay)}</td>
                  <td className={styles.cellStatus}>
                    <span
                      className={styles.statusBadge}
                      style={{ background: status.color, color: '#fff' }}
                    >
                      {status.label}
                    </span>
                  </td>
                  <td className={styles.cellPriority}>
                    <Tag color={
                      item.priority === 'Critical' ? 'red' :
                      item.priority === 'High' ? 'orange' :
                      item.priority === 'Medium' ? 'blue' : 'default'
                    }>
                      {item.priority === 'Critical' ? 'Rất QT' :
                       item.priority === 'High' ? 'QT' :
                       item.priority === 'Medium' ? 'BT' : 'Thấp'}
                    </Tag>
                  </td>
                  <td className={styles.cellActions}>
                    <Popconfirm title="Xóa khoản này?" onConfirm={() => handleDelete(item.id)}>
                      <button className={`${styles.linkBtn} ${styles.linkBtnDanger}`}>
                        <i className="fas fa-trash" />
                      </button>
                    </Popconfirm>
                  </td>
                </tr>
              );
            })}
          </tbody>
          <tfoot>
            <tr className={styles.groupTotalRow}>
              <td colSpan={2}><Text strong>Tổng {group.groupName}</Text></td>
              <td className={styles.cellMoney}><Text strong>{formatMoney(group.totalMustPay)}</Text></td>
              <td className={styles.cellMoney}><Text strong>{formatMoney(group.totalPlanned)}</Text></td>
              <td className={styles.cellMoney}><Text strong>{formatMoney(group.totalDebt)}</Text></td>
              <td className={styles.cellMoney}><Text strong>{formatMoney(group.totalActual)}</Text></td>
              <td colSpan={5}></td>
            </tr>
          </tfoot>
        </table>
      </div>
    ));
  };

  const renderEditMode = () => (
    <table className={styles.table}>
      <thead>
        <tr>
          <th className={styles.thItem}>Mã CP</th>
          <th className={styles.thItem}>Tên chi phí</th>
          <th className={styles.thGroup}>Nhóm</th>
          <th className={styles.thPriority}>Mức độ</th>
          <th className={styles.thMustPay}>Phải chi</th>
          <th className={styles.thPlanned}>Dự chi</th>
        </tr>
      </thead>
      <tbody>
        {sortedEditCodes.map((cc) => (
          <tr key={cc.id} className={styles.editRow}>
            <td className={styles.cellItem}><Text strong>{cc.code}</Text></td>
            <td className={styles.cellItem}>{cc.name}</td>
            <td className={styles.cellGroup}><Tag>{cc.groupName || 'Chi phí'}</Tag></td>
            <td className={styles.cellPriority}>
              <Tag color={
                cc.priority === 'Critical' ? 'red' :
                cc.priority === 'High' ? 'orange' :
                cc.priority === 'Medium' ? 'blue' : 'default'
              }>
                {cc.priority === 'Critical' ? 'Rất QT' :
                 cc.priority === 'High' ? 'QT' :
                 cc.priority === 'Medium' ? 'BT' : 'Thấp'}
              </Tag>
            </td>
            <td className={styles.cellMoney}>
              <input
                type="number"
                className={styles.editInput}
                value={editValues[cc.code]?.mustPay ?? '0'}
                onChange={(e) => handleEditChange(cc.code, 'mustPay', e.target.value)}
                placeholder="0"
              />
            </td>
            <td className={styles.cellMoney}>
              <input
                type="number"
                className={styles.editInput}
                value={editValues[cc.code]?.planned ?? '0'}
                onChange={(e) => handleEditChange(cc.code, 'planned', e.target.value)}
                placeholder="0"
              />
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  );

  const renderContent = () => {
    if (loading) {
      return <div className={styles.loadingState}><Spin /></div>;
    }

    if (costCodes.length === 0) {
      return (
        <div className={styles.emptyState}>
          <p>Chưa có mã chi phí. Vui lòng khai báo mã chi phí trước.</p>
        </div>
      );
    }

    if (editMode) return renderEditMode();
    return renderViewMode();
  };

  return (
    <div className={styles.page}>
      <Title>Khai báo chi phí dự kiến</Title>

      <Card style={{ marginBottom: 16 }}>
        <div className={styles.filterBar}>
          <div className={styles.filterItem}>
            <label className={styles.filterLabel}>Năm</label>
            <input
              type="number"
              className={styles.filterInput}
              value={year}
              onChange={(e) => setYear(parseInt(e.target.value) || now.getFullYear())}
              style={{ width: 80 }}
            />
          </div>
          <div className={styles.filterItem}>
            <label className={styles.filterLabel}>Tháng</label>
            <select
              className={styles.filterInput}
              value={month}
              onChange={(e) => setMonth(parseInt(e.target.value))}
              style={{ width: 100 }}
            >
              {Array.from({ length: 12 }, (_, i) => (
                <option key={i + 1} value={i + 1}>Tháng {i + 1}</option>
              ))}
            </select>
          </div>
          <div className={styles.filterItem}>
            <label className={styles.filterLabel}>Chi nhánh</label>
            <input
              className={styles.filterInput}
              value={branchCode}
              onChange={(e) => setBranchCode(e.target.value)}
              placeholder="HQ"
              style={{ width: 100 }}
            />
          </div>

          <div style={{ display: 'flex', gap: 8, alignItems: 'flex-end', marginLeft: 'auto' }}>
            {editMode ? (
              <>
                <Button variant="primary" onClick={handleSave} disabled={saving}>
                  {saving ? 'Đang lưu...' : 'Lưu'}
                </Button>
                <Button onClick={handleCancelEdit}>Hủy</Button>
              </>
            ) : (
              <>
                <Button variant="primary" onClick={handleEnterEdit}>
                  <i className="fas fa-edit" style={{ marginRight: 6 }} />
                  Khai báo
                </Button>
                <Button onClick={fetchData}>
                  <i className="fas fa-sync" style={{ marginRight: 6 }} />
                  Làm mới
                </Button>
              </>
            )}
          </div>
        </div>
      </Card>

      {/* Summary bar */}
      {!editMode && allItems.length > 0 && (
        <div className={styles.summaryRow}>
          <div className={styles.summaryItem}>
            <span className={styles.summaryLabel}>Tổng tiền dự chi toàn bộ</span>
            <span className={styles.summaryValueMain}>{formatMoney(grandTotalPlanned)}</span>
          </div>
          <div className={styles.summaryItem}>
            <span className={styles.summaryLabel}>Tổng phải chi</span>
            <span className={styles.summaryValue}>{formatMoney(grandTotalMustPay)}</span>
          </div>
          <div className={styles.summaryItem}>
            <span className={styles.summaryLabel}>Tổng nợ</span>
            <span className={styles.summaryValue} style={{ color: grandTotalDebt > 0 ? '#ff4d4f' : '#52c41a' }}>
              {formatMoney(grandTotalDebt)}
            </span>
          </div>
          <div className={styles.summaryItem}>
            <span className={styles.summaryLabel}>Tổng thực chi</span>
            <span className={styles.summaryValue}>{formatMoney(grandTotalActual)}</span>
          </div>
        </div>
      )}

      {/* Group tabs */}
      {!editMode && allItems.length > 0 && (
        <div className={styles.groupTabs}>
          <button
            className={`${styles.groupTab} ${!filteredGroup ? styles.groupTabActive : ''}`}
            onClick={() => setActiveGroup(null)}
          >
            Tất cả
          </button>
          {allGroups.map((g) => (
            <button
              key={g}
              className={`${styles.groupTab} ${filteredGroup === g ? styles.groupTabActive : ''}`}
              onClick={() => setActiveGroup(g)}
            >
              {g}
            </button>
          ))}
        </div>
      )}

      {renderContent()}
    </div>
  );
}
